-- FSI_DEMO_DB.PAYMENTS.RISK_EVENTS

CREATE OR REPLACE TABLE FSI_DEMO_DB.PAYMENTS.RISK_EVENTS (

    EVENT_ID VARCHAR(20) NOT NULL,
    TRANSACTION_ID VARCHAR(30),
    MERCHANT_ID VARCHAR(20),
    EVENT_TIMESTAMP TIMESTAMP_NTZ(9),
    EVENT_TYPE VARCHAR(50),
    RISK_SCORE NUMBER(5,4),
    RISK_FACTORS VARCHAR(16777216),
    RULE_TRIGGERED VARCHAR(100),
    MODEL_VERSION VARCHAR(20),
    ACTION_TAKEN VARCHAR(50),
    REVIEW_STATUS VARCHAR(30),
    REVIEWER_ID VARCHAR(20),
    REVIEW_DATE TIMESTAMP_NTZ(9),
    REVIEW_NOTES VARCHAR(16777216),
    FALSE_POSITIVE BOOLEAN,
    CREATED_AT TIMESTAMP_NTZ(9) DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (EVENT_ID)

);



